48	@Controller("/api/analysis")
49	public class AnalysisController {
50	
51	    private Path getBrainPath(String flavor) {
52	        if (flavor == null || flavor.isEmpty()) flavor = "antigravity-cli";
53	        return Paths.get(System.getProperty("user.home"), ".gemini", flavor, "brain");
54	    }
55	
56	    private static final int MAX_TOKENS_PER_CHUNK = 100_000;
57	    private static final Map<String, ProgressState> progressMap = new ConcurrentHashMap<>();
58	
59	    @Serdeable
60	    public record ProgressState(int progress, String phase) {}
61	
62	    @Get(value = "/conversations/{id}/progress", produces = "application/json")
63	    public ProgressResponse getProgress(@PathVariable String id) {
64	        ProgressState state = progressMap.get(id);
65	        if (state == null) {
66	            return new ProgressResponse("", -1);
67	        }
68	        return new ProgressResponse(state.phase(), state.progress());
69	    }
70	
71	    @Serdeable
72	    public record ProgressResponse(String phase, int progress) {}
73	
74	    private final AnalyzerService analyzerService;
75	    private final ExecutorService executor;
76	
77	    @Inject
78	    public AnalysisController(
79	        AnalyzerService analyzerService,
80	        @Named(TaskExecutors.IO) ExecutorService executor
81	    ) {
82	        this.analyzerService = analyzerService;
83	        this.executor = executor;
84	    }
85	
86	    private void splitIntoSafeChunks(
87	        List<String> lines,
88	        TokenCountEstimator estimator,
89	        int maxTokens,
90	        List<List<String>> safeChunks
91	    ) {
92	        if (lines.isEmpty()) return;
93	        String text = String.join("\n", lines);
94	        try {
95	            int tokens = estimator.estimateTokenCountInText(text);
96	            if (tokens <= maxTokens || lines.size() == 1) {
97	                safeChunks.add(lines);
98	            } else {
99	                int mid = lines.size() / 2;
100	                splitIntoSafeChunks(lines.subList(0, mid), estimator, maxTokens, safeChunks);
101	                splitIntoSafeChunks(
102	                    lines.subList(mid, lines.size()),
103	                    estimator,
104	                    maxTokens,
105	                    safeChunks
106	                );
107	            }
108	        } catch (Exception e) {
109	            int fallbackTokens = text.length() / 2;
110	            if (fallbackTokens <= maxTokens || lines.size() == 1) {
111	                safeChunks.add(lines);
112	            } else {
113	                int mid = lines.size() / 2;
114	                splitIntoSafeChunks(lines.subList(0, mid), estimator, maxTokens, safeChunks);
115	                splitIntoSafeChunks(
116	                    lines.subList(mid, lines.size()),
117	                    estimator,
118	                    maxTokens,
119	                    safeChunks
120	                );
121	            }
122	        }
123	    }
124	
125	    private static final Map<String, Object> runningTasks = new ConcurrentHashMap<>();
126	
127	    @ExecuteOn(TaskExecutors.IO)
128	    @Get(value = "/conversations/{id}/summarize", produces = "application/json")
129	    public String summarizeConversation(
130	        @PathVariable String id,
131	        @QueryValue Optional<Boolean> force,
132	        @QueryValue Optional<String> flavor
133	    ) throws IOException {
134	        String apiKey = System.getenv("GEMINI_API_KEY");
135	        if (apiKey == null || apiKey.isEmpty()) {
136	            return "{\"summary\": \"Error: GEMINI_API_KEY environment variable is not set. Cannot use LangChain4j analysis.\"}";
137	        }
138	
139	        if (runningTasks.putIfAbsent(id, new Object()) != null) {
140	            return "{\"summary\": \"Analysis is already running in the background for this conversation. Please wait a moment and refresh.\"}";
141	        }
142	
143	        try {
144	            Path brainPath = getBrainPath(flavor.orElse("antigravity-cli"));
145	            Path transcriptPath = brainPath
146	                .resolve(id)
147	                .resolve(".system_generated")
148	                .resolve("logs")
149	                .resolve("transcript.jsonl");
150	            if (!Files.exists(transcriptPath)) {
151	                return "{\"summary\": \"No transcript found.\"}";
152	            }
153	
154	            boolean forceRecompute = force.orElse(false);
155	            Path summaryJsonPath = brainPath
156	                .resolve(id)
157	                .resolve(".system_generated")
158	                .resolve("logs")
159	                .resolve("summary.json");
160	            Path shortTitlePath = brainPath
161	                .resolve(id)
162	                .resolve(".system_generated")
163	                .resolve("logs")
164	                .resolve("short_title.txt");
165	
166	            if (!forceRecompute && Files.exists(summaryJsonPath)) {
167	                String json = Files.readString(summaryJsonPath);
168	                return json;
169	            } else if (forceRecompute) {
170	                Files.deleteIfExists(summaryJsonPath);
171	            }
172	
173	            ObjectMapper mapper = new ObjectMapper();
174	            AnalysisResponse responseObj = null;
175	
176	            try {
177	                List<String> allLines = Files.readAllLines(transcriptPath);
178	                List<List<String>> sequences = new ArrayList<>();
179	                List<String> currentSequence = new ArrayList<>();
180	
181	                for (String line : allLines) {
182	                    if (line.trim().isEmpty()) continue;
183	                    try {
184	                        JsonNode node = mapper.readTree(line);
185	                        String type = node.path("type").asText("");
186	                        if (
187	                            "USER_INPUT".equals(type) ||
188	                            "USER_EXPLICIT".equals(node.path("source").asText(""))
189	                        ) {
190	                            if (!currentSequence.isEmpty()) {
191	                                sequences.add(deduplicateSequence(currentSequence));
192	                                currentSequence = new ArrayList<>();
193	                            }
194	                            String content = node.path("content").asText("");
195	                            currentSequence.add(
196	                                "USER REQUEST: " +
197	                                content.substring(0, Math.min(2000, content.length()))
198	                            );
199	                        } else if (
200	                            "PLANNER_RESPONSE".equals(type) ||
201	                            "MODEL".equals(node.path("source").asText(""))
202	                        ) {
203	                            JsonNode tools = node.path("tool_calls");
204	                            if (!tools.isMissingNode() && tools.isArray()) {
205	                                for (JsonNode tool : tools) {
206	                                    String name = tool.path("name").asText("unknown");
207	                                    String action = tool
208	                                        .path("arguments")
209	                                        .path("toolAction")
210	                                        .asText("");
211	                                    String tgt = tool
212	                                        .path("arguments")
213	                                        .path("TargetFile")
214	                                        .asText("");
215	                                    if (tgt.isEmpty()) tgt =
216	                                        tool.path("arguments").path("CommandLine").asText("");
217	                                    currentSequence.add(
218	                                        "AGENT ACTION: [" + name + "] " + action + " -> " + tgt
219	                                    );
220	                                }
221	                            }
222	                        } else if (
223	                            node.has("error") ||
224	                            (
225	                                node.has("content") &&
226	                                node.path("content").asText("").contains("Exception")
227	                            )
228	                        ) {
229	                            String err = node.path("content").asText("");
230	                            currentSequence.add(
231	                                "SYSTEM EVENT/ERROR: " +
232	                                err.substring(0, Math.min(500, err.length()))
233	                            );
234	                        }
235	                    } catch (Exception e) {
236	                        // skip malformed
237	                    }
238	                }
239	                if (!currentSequence.isEmpty()) {
240	                    sequences.add(deduplicateSequence(currentSequence));
241	                }
242	
243	                TokenCountEstimator estimator = GoogleGenAiTokenCountEstimator
244	                    .builder()
245	                    .apiKey(apiKey)
246	                    .modelName("gemini-3.5-flash")
247	                    .build();
248	
249	                progressMap.put(id, new ProgressState(5, "Estimating Tokens & Chunking...")); // Phase 1: Estimating
250	
251	                List<String> combinedLines = new ArrayList<>();
252	                for (List<String> seq : sequences) {
253	                    combinedLines.addAll(seq);
254	                }
255	                List<List<String>> optimalChunks = new ArrayList<>();
256	                splitIntoSafeChunks(combinedLines, estimator, MAX_TOKENS_PER_CHUNK, optimalChunks);
257	
258	                System.out.println(
259	                    "Total optimal chunks to process in parallel: " + optimalChunks.size()
260	                );
261	
262	                progressMap.put(id, new ProgressState(0, "Starting chunk processing...")); // start at 0%
263	
264	                List<Future<AnalysisResponse>> futures = new ArrayList<>();
265	                AtomicInteger completed = new AtomicInteger(0);
266	
267	                // Limit to 20 concurrent LLM requests, as we have drastically reduced chunk count
268	                Semaphore rateLimitSemaphore = new Semaphore(20);
269	
270	                for (List<String> chunkLines : optimalChunks) {
271	                    futures.add(
272	                        executor.submit(() -> {
273	                            try {
274	                                rateLimitSemaphore.acquire();
275	                            } catch (InterruptedException e) {
276	                                Thread.currentThread().interrupt();
277	                                return null;
278	                            }
279	
280	                            try {
281	                                String chunk = String.join("\n", chunkLines);
282	                                AnalysisResponse seqResponse = null;
283	                                try {
284	                                    seqResponse = analyzerService.analyze(chunk);
285	                                } catch (Exception e) {
286	                                    System.err.println(
287	                                        "Failed to parse chunk from LLM: " + e.getMessage()
288	                                    );
289	                                    e.printStackTrace();
290	                                    // Ignore unparseable chunk
291	                                }
292	
293	                                int comp = completed.incrementAndGet();
294	                                // Scale parallel processing to 90% of the total progress
295	                                int pct = (int) Math.round((comp * 90.0) / optimalChunks.size());
296	                                String phaseMsg =
297	                                    "Processing chunk " +
298	                                    comp +
299	                                    " of " +
300	                                    optimalChunks.size() +
301	                                    "...";
302	
303	                                // Prevent progress moving backwards if futures finish out of order
304	                                progressMap.compute(
305	                                    id,
306	                                    (k, v) -> {
307	                                        if (v == null || pct > v.progress()) {
308	                                            return new ProgressState(pct, phaseMsg);
309	                                        }
310	                                        return v;
311	                                    }
312	                                );
313	
314	                                return seqResponse;
315	                            } finally {
316	                                rateLimitSemaphore.release();
317	                            }
318	                        })
319	                    );
320	                }
321	
322	                List<AnalysisResponse> seqResponses = new ArrayList<>();
323	                for (Future<AnalysisResponse> f : futures) {
324	                    AnalysisResponse r = f.get();
325	                    if (r != null) seqResponses.add(r);
326	                }
327	
328	                if (seqResponses.isEmpty()) {
329	                    return "{\"summary\": \"No transcript lines found.\"}";
330	                } else if (seqResponses.size() == 1) {
331	                    responseObj = seqResponses.get(0);
332	                } else {
333	                    progressMap.put(id, new ProgressState(90, "Consolidating final analysis..."));
334	
335	                    // Keep the progress bar moving smoothly during the long final LLM consolidation
336	                    AtomicBoolean consolidationDone = new AtomicBoolean(false);
337	                    Future<?> fakeProgress = executor.submit(() -> {
338	                        int p = 90;
339	                        while (!consolidationDone.get() && p < 99) {
340	                            try {
341	                                Thread.sleep(2000);
342	                            } catch (InterruptedException e) {
343	                                break;
344	                            }
345	                            if (!consolidationDone.get()) {
346	                                int nextP = p + 1;
347	                                progressMap.put(
348	                                    id,
349	                                    new ProgressState(nextP, "Consolidating final analysis...")
350	                                );
351	                                p = nextP;
352	                            }
353	                        }
354	                    });
355	
356	                    try {
357	                        responseObj =
358	                            recursivelyConsolidate(seqResponses, estimator, mapper, 500_000);
359	                    } finally {
360	                        consolidationDone.set(true);
361	                        fakeProgress.cancel(true);
362	                    }
363	                }
364	
365	                progressMap.put(id, new ProgressState(100, "Done"));
366	
367	                String jsonResponse = mapper.writeValueAsString(responseObj);
368	
369	                // Try to extract shortTitle for shortTitlePath caching
370	                try {
371	                    String title = responseObj.shortTitle();
372	                    if (title != null && !title.isEmpty()) {
373	                        Files.writeString(shortTitlePath, title.trim());
374	                    }
375	                } catch (Exception e) {}
376	
377	                try {
378	                    Files.writeString(summaryJsonPath, jsonResponse);
379	                    return jsonResponse;
380	                } catch (Exception e) {
381	                    throw new Exception("Invalid JSON response");
382	                }
383	            } catch (Exception e) {
384	                System.err.println("Exception caught during analysis:");
385	                e.printStackTrace();
386	                try {
387	                    return mapper.writeValueAsString(
388	                        Map.of("summary", "Error generating summary: " + e.getMessage())
389	                    );
390	                } catch (Exception ex) {
391	                    return "{\"summary\": \"Error generating summary: Unknown error\"}";
392	                }
393	            } finally {
394	                progressMap.remove(id);
395	            }
396	        } finally {
397	            runningTasks.remove(id);
398	        }
399	    }
400	
401	    private AnalysisResponse recursivelyConsolidate(
402	        List<AnalysisResponse> responses,
403	        TokenCountEstimator estimator,
404	        ObjectMapper mapper,
405	        int maxTokens
406	    ) throws Exception {
407	        String json = mapper.writeValueAsString(responses);
408	        try {
409	            int tokens = estimator.estimateTokenCountInText(json);
410	            if (tokens <= maxTokens) {
411	                return analyzerService.consolidateAnalysis(json);
412	            }
413	        } catch (Exception e) {
414	            // fallback
415	        }
416	
417	        int mid = responses.size() / 2;
418	        AnalysisResponse r1 = recursivelyConsolidate(
419	            responses.subList(0, mid),
420	            estimator,
421	            mapper,
422	            maxTokens
423	        );
424	        AnalysisResponse r2 = recursivelyConsolidate(
425	            responses.subList(mid, responses.size()),
426	            estimator,
427	            mapper,
428	            maxTokens
429	        );
430	        return analyzerService.consolidateAnalysis(mapper.writeValueAsString(List.of(r1, r2)));
431	    }
432	
433	    private List<String> deduplicateSequence(List<String> sequence) {
434	        if (sequence.isEmpty()) return sequence;
435	        List<String> deduped = new ArrayList<>();
436	        String lastLine = null;
437	        int count = 0;
438	        for (String line : sequence) {
439	            if (line.equals(lastLine)) {
440	                count++;
441	            } else {
442	                if (count > 1) {
443	                    deduped.set(deduped.size() - 1, lastLine + " (repeated " + count + " times)");
444	                }
445	                deduped.add(line);
446	                lastLine = line;
447	                count = 1;
448	            }
449	        }
450	        if (count > 1) {
451	            deduped.set(deduped.size() - 1, lastLine + " (repeated " + count + " times)");
452	        }
453	        return deduped;
454	    }
455	}
