16	import { state, escapeHtml } from "./utils.js";
17	
18	export async function triggerAnalysis(sessionId, force) {
19	  const btn = document.getElementById("summarize-btn");
20	  const aiContainer = document.getElementById("ai-summary-container");
21	  const aiText = document.getElementById("ai-summary-text");
22	
23	  if (force) {
24	    btn.disabled = true;
25	    btn.innerHTML = '<span class="sparkle-icon">⏳</span> Recomputing...';
26	  }
27	
28	  aiContainer.classList.remove("hidden");
29	
30	  if (force) {
31	    const content = document.getElementById("ai-summary-content");
32	    content.classList.remove("collapsed");
33	    const chevron = document
34	      .getElementById("ai-summary-header")
35	      .querySelector(".chevron");
36	    chevron.style.transform = "rotate(90deg)";
37	    aiText.innerHTML = "<em>Recomputing transcript analysis...</em>";
38	  } else if (!state.summaryCache[sessionId]) {
39	    aiText.innerHTML = "<em>Loading analysis...</em>";
40	  } else {
41	    aiText.innerHTML = state.summaryCache[sessionId];
42	    return; // already cached and not forced
43	  }
44	
45	  let currentPollSessionId = sessionId;
46	  state.currentPollSessionId = sessionId;
47	
48	  try {
49	    const flavor = encodeURIComponent(
50	      document.getElementById("flavor-select").value
51	    );
52	    let url = `/api/analysis/conversations/${sessionId}/summarize?flavor=${flavor}`;
53	    if (force) url += "&force=true";
54	
55	    // Progress UI
56	    if (force || !state.summaryCache[sessionId]) {
57	      const pContainer = document.createElement("div");
58	      pContainer.innerHTML = `
59	                <div style="font-size: 0.9rem; color: var(--text-secondary); margin-bottom: 8px;"><span id="progress-phase">Starting analysis...</span> <span id="progress-text">0%</span></div>
60	                <div style="width: 100%; height: 6px; background: rgba(255,255,255,0.1); border-radius: 3px; overflow: hidden;">
61	                    <div id="progress-bar" style="width: 0%; height: 100%; background: var(--accent-blue); transition: width 0.3s ease-out;"></div>
62	                </div>
63	            `;
64	      aiText.innerHTML = "";
65	      aiText.appendChild(pContainer);
66	    }
67	
68	    let polling = true;
69	    const pollProgress = async () => {
70	      while (polling && state.currentPollSessionId === sessionId) {
71	        try {
72	          const pres = await fetch(
73	            `/api/analysis/conversations/${sessionId}/progress`
74	          );
75	          if (pres.ok) {
76	            const pdata = await pres.json();
77	            if (
78	              pdata.progress >= 0 &&
79	              state.currentPollSessionId === sessionId
80	            ) {
81	              const phase = document.getElementById("progress-phase");
82	              const pt = document.getElementById("progress-text");
83	              const pb = document.getElementById("progress-bar");
84	              if (phase) phase.innerText = pdata.phase;
85	              if (pt) pt.innerText = pdata.progress + "%";
86	              if (pb) pb.style.width = pdata.progress + "%";
87	            }
88	          }
89	        } catch (e) {}
90	        await new Promise((r) => setTimeout(r, 1000));
91	      }
92	    };
93	
94	    pollProgress();
95	
96	    const res = await fetch(url);
97	    polling = false; // stop polling
98	
99	    const data = await res.json();
100	
101	    let html = "";
102	    if (data.summary) {
103	      html += `<p style="font-size: 1.05rem; margin-bottom: 24px; line-height: 1.6; color: var(--text-primary);">${escapeHtml(
104	        data.summary
105	      )}</p>`;
106	    }
107	
108	    if (data.flow && data.flow.length > 0) {
109	      html += `<h4 style="color: var(--accent-blue); margin-top: 16px; margin-bottom: 12px; font-size: 0.9rem; text-transform: uppercase; letter-spacing: 0.05em;">Conversation Flow</h4>`;
110	      html += `<ul style="list-style-type: none; padding-left: 0; margin-bottom: 24px;">`;
111	      data.flow.forEach((item, i) => {
112	        html += `<li style="margin-bottom: 10px; padding-left: 24px; position: relative; color: var(--text-secondary); line-height: 1.5;">
113	                    <span style="position: absolute; left: 0; top: 0; color: var(--accent-blue);">→</span>${escapeHtml(
114	                      item
115	                    )}
116	                </li>`;
117	      });
118	      html += `</ul>`;
119	    }
120	
121	    if (data.agentActions && data.agentActions.length > 0) {
122	      html += `<h4 style="color: var(--accent-purple); margin-top: 16px; margin-bottom: 12px; font-size: 0.9rem; text-transform: uppercase; letter-spacing: 0.05em;">Agent Actions Breakdown</h4>`;
123	      html += `<div style="display: flex; flex-direction: column; gap: 12px; margin-bottom: 24px;">`;
124	      data.agentActions.forEach((action) => {
125	        html += `<div style="background: rgba(30, 41, 59, 0.4); border: 1px solid rgba(255,255,255,0.05); border-radius: 6px; padding: 14px;">
126	                    <div style="font-weight: 600; color: var(--text-primary); margin-bottom: 6px; font-family: var(--font-mono); font-size: 0.85rem;">${escapeHtml(
127	                      action.action
128	                    )}</div>
129	                    <div style="font-size: 0.9rem; color: var(--text-secondary); line-height: 1.5;">${escapeHtml(
130	                      action.description
131	                    )}</div>
132	                </div>`;
133	      });
134	      html += `</div>`;
135	    }
136	
137	    if (data.issues && data.issues.length > 0) {
138	      html += `<h4 style="color: var(--error); margin-top: 16px; margin-bottom: 12px; font-size: 0.9rem; text-transform: uppercase; letter-spacing: 0.05em;">Issues & Circumventions</h4>`;
139	      html += `<div style="display: flex; flex-direction: column; gap: 12px; margin-bottom: 24px;">`;
140	      data.issues.forEach((issue) => {
141	        html += `<div style="background: rgba(239, 68, 68, 0.05); border: 1px solid rgba(239, 68, 68, 0.2); border-radius: 6px; padding: 14px;">
142	                    <div style="font-weight: 600; color: #fca5a5; margin-bottom: 6px; display: flex; align-items: center; gap: 8px; font-size: 0.85rem;">
143	                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="8" x2="12" y2="12"></line><line x1="12" y1="16" x2="12.01" y2="16"></line></svg>
144	                        ISSUE
145	                    </div>
146	                    <div style="font-size: 0.9rem; color: var(--text-primary); line-height: 1.5;">${escapeHtml(
147	                      issue.error
148	                    )}</div>`;
149	
150	        const circumvention = issue.circumvention
151	          ? issue.circumvention.trim()
152	          : "";
153	        const isUnresolved =
154	          !circumvention ||
155	          circumvention.toLowerCase() === "null" ||
156	          circumvention.toLowerCase() === "none" ||
157	          circumvention.toLowerCase() === "n/a";
158	
159	        if (!isUnresolved) {
160	          html += `
161	                    <div style="font-weight: 600; color: var(--success); margin-top: 12px; margin-bottom: 6px; display: flex; align-items: center; gap: 8px; font-size: 0.85rem;">
162	                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"></path><polyline points="22 4 12 14.01 9 11.01"></polyline></svg>
163	                        RESOLUTION
164	                    </div>
165	                    <div style="font-size: 0.9rem; color: var(--text-secondary); line-height: 1.5;">${escapeHtml(
166	                      circumvention
167	                    )}</div>`;
168	        } else {
169	          html += `
170	                    <div style="font-weight: 600; color: #64748b; margin-top: 12px; margin-bottom: 6px; display: flex; align-items: center; gap: 8px; font-size: 0.85rem; font-style: italic;">
171	                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="4.93" y1="4.93" x2="19.07" y2="19.07"></line></svg>
172	                        UNRESOLVED
173	                    </div>`;
174	        }
175	
176	        html += `</div>`;
177	      });
178	      html += `</div>`;
179	    }
180	
181	    if (data.recommendations && data.recommendations.length > 0) {
182	      html += `<h4 style="color: #10b981; margin-top: 16px; margin-bottom: 12px; font-size: 0.9rem; text-transform: uppercase; letter-spacing: 0.05em;">Future Recommendations</h4>`;
183	      html += `<div style="display: flex; flex-direction: column; gap: 8px; margin-bottom: 24px;">`;
184	      data.recommendations.forEach((rec) => {
185	        html += `<div style="background: rgba(16, 185, 129, 0.05); border: 1px solid rgba(16, 185, 129, 0.2); border-radius: 6px; padding: 12px; font-size: 0.9rem; color: var(--text-primary); line-height: 1.5; display: flex; align-items: flex-start; gap: 10px;">
186	                    <svg style="flex-shrink: 0; margin-top: 2px; color: #10b981;" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 2v20M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>
187	                    <span>${escapeHtml(rec)}</span>
188	                </div>`;
189	      });
190	      html += `</div>`;
191	    }
192	
193	    aiText.innerHTML =
194	      html || "<span style='color:red;'>Failed to parse analysis data.</span>";
195	    state.summaryCache[sessionId] = aiText.innerHTML;
196	
197	    if (data.shortTitle) {
198	      const sidebarItem = document.querySelector(
199	        `.conv-item[data-id="${sessionId}"] .conv-id`
200	      );
201	      if (sidebarItem) {
202	        sidebarItem.innerText = data.shortTitle;
203	      }
204	      document.getElementById("current-session-title").innerText =
205	        data.shortTitle;
206	    }
207	  } catch (e) {
208	    aiText.innerHTML =
209	      "<span style='color:red;'>Error analyzing transcript.</span>";
210	  } finally {
211	    if (force) {
212	      btn.innerHTML = '<span class="sparkle-icon">✨</span> Recompute Analysis';
213	      btn.disabled = false;
214	    }
215	  }
216	}
