200	function renderConversationsList() {
201	  const list = document.getElementById("conversations-list");
202	  list.innerHTML = "";
203	
204	  let filtered = [...allConversations];
205	  const searchTerm =
206	    document.getElementById("conversation-search")?.value.toLowerCase() || "";
207	
208	  if (searchTerm) {
209	    filtered = filtered.filter(
210	      (c) =>
211	        c.summary.toLowerCase().includes(searchTerm) ||
212	        c.id.toLowerCase().includes(searchTerm)
213	    );
214	  }
215	
216	  if (!sortDescending) {
217	    filtered.reverse();
218	  }
219	
220	  if (filtered.length === 0) {
221	    list.innerHTML = '<div class="loading-state">No sessions found</div>';
222	    return;
223	  }
224	
225	  filtered.forEach((conv) => {
226	    const div = document.createElement("div");
227	    div.className = "conv-item";
228	    div.dataset.id = conv.id;
229	    div.dataset.summary = conv.summary;
230	    div.dataset.updatedAt = conv.updatedAt || "0";
231	    div.innerHTML = `<div class="conv-id">${escapeHtml(conv.summary)}</div>`;
232	    list.appendChild(div);
233	  });
234	
235	  // Event Delegation for conversation selection
236	  if (!list.dataset.listenerAttached) {
237	    list.addEventListener("click", (e) => {
238	      const item = e.target.closest(".conv-item");
239	      if (item && item.dataset.id) {
240	        selectConversation(item.dataset.id, item);
241	      }
242	    });
243	
244	    // Custom Popover Logic
245	    const popover = document.getElementById("conv-popover");
246	    list.addEventListener("mouseover", (e) => {
247	      const item = e.target.closest(".conv-item");
248	      if (item && item.dataset.id && popover) {
249	        document.getElementById("popover-title").innerText =
250	          item.dataset.summary;
251	        document.getElementById("popover-id").innerText = item.dataset.id;
252	
253	        const timestamp = parseInt(item.dataset.updatedAt, 10);
254	        let timeStr = "Unknown time";
255	        if (timestamp > 0) {
256	          const d = new Date(timestamp);
257	          const dateText = d.toLocaleDateString("en-US", {
258	            year: "numeric",
259	            month: "long",
260	            day: "numeric",
261	          });
262	
263	          const diffMs = Date.now() - timestamp;
264	          const diffMin = Math.floor(diffMs / (1000 * 60));
265	          const diffHour = Math.floor(diffMs / (1000 * 60 * 60));
266	          const diffDay = Math.floor(diffMs / (1000 * 60 * 60 * 24));
267	
268	          let relStr;
269	          if (diffDay > 0)
270	            relStr = diffDay === 1 ? "1 day ago" : `${diffDay} days ago`;
271	          else if (diffHour > 0)
272	            relStr = diffHour === 1 ? "1 hour ago" : `${diffHour} hours ago`;
273	          else if (diffMin > 0)
274	            relStr = diffMin === 1 ? "1 minute ago" : `${diffMin} minutes ago`;
275	          else relStr = "just now";
276	
277	          timeStr = `${dateText} (${relStr})`;
278	        }
279	        document.getElementById("popover-time").innerHTML = timeStr;
280	
281	        popover.classList.remove("hidden");
282	      }
283	    });
284	
285	    list.addEventListener("mousemove", (e) => {
286	      const item = e.target.closest(".conv-item");
287	      if (item && popover && !popover.classList.contains("hidden")) {
288	        let top = e.clientY + 15;
289	        let left = e.clientX + 15;
290	
291	        // Prevent overflow off bottom/right edges
292	        if (top + popover.offsetHeight > window.innerHeight) {
293	          top = e.clientY - popover.offsetHeight - 15;
294	        }
295	        if (left + popover.offsetWidth > window.innerWidth) {
296	          left = e.clientX - popover.offsetWidth - 15;
297	        }
298	
299	        popover.style.top = `${top}px`;
300	        popover.style.left = `${left}px`;
301	      }
302	    });
303	
304	    list.addEventListener("mouseout", (e) => {
305	      const item = e.target.closest(".conv-item");
306	      if (item && popover) {
307	        if (e.relatedTarget && item.contains(e.relatedTarget)) return;
308	        popover.classList.add("hidden");
309	      }
310	    });
311	
312	    list.dataset.listenerAttached = "true";
313	  }
314	
315	  // Check if there's a session ID in the URL hash
316	  const hashId = window.location.hash.substring(1);
317	  const targetDiv = hashId
318	    ? list.querySelector(`[data-id="${hashId}"]`)
319	    : list.firstElementChild;
320	
321	  if (targetDiv) {
322	    targetDiv.click();
323	  }
324	}
