16	import { escapeHtml, formatTime } from "./utils.js";
17	
18	let modal, modalTitle, modalContent;
19	
20	export function initUI() {
21	  modal = document.getElementById("file-modal");
22	  modalTitle = document.getElementById("file-modal-title");
23	  modalContent = document.getElementById("file-modal-content");
24	  const closeBtn = document.getElementById("close-modal-btn");
25	
26	  if (closeBtn) {
27	    closeBtn.addEventListener("click", () => {
28	      modal.classList.add("hidden");
29	    });
30	  }
31	
32	  if (modal) {
33	    modal.addEventListener("click", (e) => {
34	      if (e.target === modal) {
35	        modal.classList.add("hidden");
36	      }
37	    });
38	  }
39	
40	  // Intercept file:// links using event delegation
41	  document.addEventListener("click", async (e) => {
42	    const link = e.target.closest("a");
43	    if (link && link.href && link.href.startsWith("file://")) {
44	      e.preventDefault();
45	
46	      let path = link.href.replace("file://", "");
47	      path = path.split("#")[0]; // Strip line numbers hash like #L10-L20
48	      path = decodeURIComponent(path);
49	
50	      try {
51	        const res = await fetch(
52	          `/api/brain/file?path=${encodeURIComponent(path)}`
53	        );
54	        if (!res.ok) {
55	          if (res.status === 404) throw new Error("File not found");
56	          throw new Error("Failed to load file");
57	        }
58	        const content = await res.text();
59	
60	        modalTitle.innerText = path;
61	
62	        const ext = path.split(".").pop().toLowerCase();
63	        const supportedExts = [
64	          "js",
65	          "json",
66	          "java",
67	          "html",
68	          "css",
69	          "md",
70	          "sh",
71	          "bash",
72	          "yaml",
73	          "yml",
74	          "xml",
75	          "sql",
76	          "kt",
77	          "kts",
78	          "gradle",
79	          "properties",
80	          "py",
81	          "go",
82	          "rs",
83	          "cpp",
84	          "c",
85	          "ts",
86	          "jsx",
87	          "tsx",
88	        ];
89	        let langClass = "";
90	        if (supportedExts.includes(ext)) {
91	          langClass = `language-${ext}`;
92	        }
93	
94	        modalContent.className = langClass;
95	        modalContent.innerHTML = escapeHtml(content);
96	
97	        if (langClass && window.hljs) {
98	          delete modalContent.dataset.highlighted;
99	          hljs.highlightElement(modalContent);
100	        }
101	
102	        modal.classList.remove("hidden");
103	      } catch (err) {
