118	function initScrubber() {
119	  const track = document.getElementById("timeline-track");
120	  if (!track) return;
121	  const thumb = document.getElementById("timeline-thumb");
122	  const label = document.getElementById("timeline-label");
123	  const scrollContainer = document.getElementById("transcript-container");
124	
125	  if (!scrollContainer) return;
126	
127	  let isDragging = false;
128	  let isTicking = false;
129	
130	  // Use IntersectionObserver to update label efficiently without getBoundingClientRect
131	  let visibleCards = new Set();
132	
133	  const updateTimelineRect = () => {
134	    if (window.timelineTotalMs > 0 && visibleCards.size > 0) {
135	      let minTs = Infinity;
136	      let maxTs = -Infinity;
137	      visibleCards.forEach((el) => {
138	        if (el.dataset.timestampStart && el.dataset.timestampEnd) {
139	          const start = parseInt(el.dataset.timestampStart, 10);
140	          const end = parseInt(el.dataset.timestampEnd, 10);
141	          if (start < minTs) minTs = start;
142	          if (end > maxTs) maxTs = end;
143	        } else if (el.dataset.timestamp) {
144	          const tsStart = parseInt(el.dataset.timestamp, 10);
145	          const tsEnd = el.dataset.timestampEnd
146	            ? parseInt(el.dataset.timestampEnd, 10)
147	            : tsStart;
148	          if (tsStart < minTs) minTs = tsStart;
149	          if (tsEnd > maxTs) maxTs = tsEnd;
150	        }
151	      });
152	
153	      if (minTs !== Infinity && maxTs !== -Infinity) {
154	        // Add a slight buffer to the width so it doesn't look like a 0px line for a single card
155	        const startPct =
156	          ((minTs - window.timelineStart) / window.timelineTotalMs) * 100;
157	        let widthPct = ((maxTs - minTs) / window.timelineTotalMs) * 100;
158	
159	        const indicator = document.getElementById("session-timeline-indicator");
160	        if (indicator) {
161	          const clampedStart = Math.max(0, Math.min(100, startPct));
162	          indicator.style.left = `calc(${clampedStart}% - ${
163	            (clampedStart / 100) * 2
164	          }px)`;
165	          indicator.style.width = widthPct + "%";
166	          indicator.style.minWidth = "2px";
167	          indicator.style.display = "block";
168	        }
169	      }
170	    }
171	  };
172	
173	  const labelObserver = new IntersectionObserver(
174	    (entries) => {
175	      entries.forEach((entry) => {
176	        if (entry.isIntersecting) {
177	          const card = entry.target;
178	          if (card.dataset.time) {
179	            label.innerText = card.dataset.time;
180	          }
181	        }
182	      });
183	    },
184	    {
185	      root: scrollContainer,
186	      rootMargin: "-10% 0px -80% 0px",
187	      threshold: 0,
188	    }
189	  );
190	
191	  const rectObserver = new IntersectionObserver(
192	    (entries) => {
193	      let changedVisibility = false;
194	      entries.forEach((entry) => {
195	        if (entry.isIntersecting) {
196	          visibleCards.add(entry.target);
197	          changedVisibility = true;
198	        } else {
199	          if (visibleCards.has(entry.target)) {
200	            visibleCards.delete(entry.target);
201	            changedVisibility = true;
202	          }
203	        }
204	      });
205	      if (changedVisibility) {
206	        updateTimelineRect();
207	      }
208	    },
209	    {
210	      root: scrollContainer,
211	      rootMargin: "0px",
212	      threshold: 0,
213	    }
214	  );
215	
216	  // Watch for new step-cards being added to the DOM and observe them
217	  const mutationObserver = new MutationObserver((mutations) => {
218	    mutations.forEach((mutation) => {
219	      mutation.addedNodes.forEach((node) => {
220	        if (node.nodeType === 1) {
221	          if (
222	            node.classList.contains("step-card") ||
223	            node.id === "timeline-bottom-marker"
224	          ) {
225	            if (node.classList.contains("step-card"))
226	              labelObserver.observe(node);
227	            rectObserver.observe(node);
228	          }
229	          node
230	            .querySelectorAll(".step-card, #timeline-bottom-marker")
231	            .forEach((card) => {
232	              if (card.classList.contains("step-card"))
233	                labelObserver.observe(card);
234	              rectObserver.observe(card);
235	            });
236	        }
237	      });
238	    });
239	  });
240	  mutationObserver.observe(scrollContainer, { childList: true, subtree: true });
241	
242	  // Only update thumb position in the scroll event, greatly reducing layout thrashing
243	  function updateScrubberThumb() {
244	    if (isTicking) return;
245	    isTicking = true;
246	
247	    window.requestAnimationFrame(() => {
248	      const scrollableHeight =
249	        scrollContainer.scrollHeight - scrollContainer.clientHeight;
250	      if (scrollableHeight <= 0) {
251	        thumb.style.top = "0px";
252	        isTicking = false;
253	        return;
254	      }
255	
256	      const scrollPerc = scrollContainer.scrollTop / scrollableHeight;
257	      const trackHeight = track.clientHeight;
258	      const thumbHeight = thumb.clientHeight;
259	
260	      const maxTop = trackHeight - thumbHeight;
261	      thumb.style.top = scrollPerc * maxTop + "px";
262	
263	      isTicking = false;
264	    });
265	  }
266	
267	  function scrollToTrackPosition(clientY) {
268	    const rect = track.getBoundingClientRect();
269	    let y = clientY - rect.top;
270	    y = Math.max(0, Math.min(y, rect.height));
271	
272	    const perc = y / rect.height;
273	    const scrollableHeight =
274	      scrollContainer.scrollHeight - scrollContainer.clientHeight;
275	    scrollContainer.scrollTo(0, perc * scrollableHeight);
276	  }
277	
278	  track.addEventListener("mousedown", (e) => {
279	    isDragging = true;
280	    track.classList.add("active");
281	    e.preventDefault(); // Prevent text selection
282	    scrollToTrackPosition(e.clientY);
283	  });
284	
285	  window.addEventListener("mousemove", (e) => {
286	    if (!isDragging) return;
287	    e.preventDefault();
288	    scrollToTrackPosition(e.clientY);
289	  });
290	
291	  window.addEventListener("mouseup", () => {
292	    isDragging = false;
293	    track.classList.remove("active");
294	  });
295	
296	  scrollContainer.addEventListener("scroll", updateScrubberThumb);
297	  setTimeout(updateScrubberThumb, 500);
298	  window.addEventListener("transcriptLoaded", updateScrubberThumb);
299	}
