            maxTokens
        );
        AnalysisResponse r2 = recursivelyConsolidate(
            responses.subList(mid, responses.size()),
            estimator,
            mapper,
            maxTokens
        );
        return analyzerService.consolidateAnalysis(mapper.writeValueAsString(List.of(r1, r2)));
    }

