package io.github.glaforge.agybrainviz;

import static org.junit.jupiter.api.Assertions.assertEquals;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import java.util.List;
import org.junit.jupiter.api.Test;

/**
 * Verifies that the analysis DTO records serialize and deserialize correctly with Jackson, which is
 * how {@link AnalysisController} writes summaries to disk and back over the wire.
 */
class AnalysisResponseSerdeTest {

    private static final ObjectMapper MAPPER = new ObjectMapper();

    @Test
    void serializesAllFieldsIncludingNestedRecords() throws Exception {
        AnalysisResponse response = new AnalysisResponse(
            "My Title",
            List.of("step one", "step two"),
            List.of(new AgentAction("edit", "edited a file")),
            List.of(new Issue("it broke", "restarted it")),
            List.of("add a CLI tool"),
            "all went fine"
        );

        JsonNode node = MAPPER.readTree(MAPPER.writeValueAsString(response));

        assertEquals("My Title", node.get("shortTitle").asText());
        assertEquals("step one", node.get("flow").get(0).asText());
        assertEquals("edit", node.get("agentActions").get(0).get("action").asText());
        assertEquals("edited a file", node.get("agentActions").get(0).get("description").asText());
        assertEquals("it broke", node.get("issues").get(0).get("error").asText());
        assertEquals("restarted it", node.get("issues").get(0).get("circumvention").asText());
        assertEquals("add a CLI tool", node.get("recommendations").get(0).asText());
        assertEquals("all went fine", node.get("summary").asText());
    }

    @Test
    void roundTripsThroughJackson() throws Exception {
        AnalysisResponse original = new AnalysisResponse(
            "Round Trip",
            List.of("a"),
            List.of(new AgentAction("run", "ran a command")),
            List.of(new Issue("oops", "fixed")),
            List.of("rec"),
            "summary text"
        );

        String json = MAPPER.writeValueAsString(original);
        AnalysisResponse restored = MAPPER.readValue(json, AnalysisResponse.class);

        assertEquals(original, restored);
    }
}

{
  "name": "agy-brain-visualizer-frontend-tests",
  "version": "0.0.0",
  "private": true,
  "description": "Dev-only test harness for the Antigravity Brain Visualizer vanilla-JS frontend modules. The application ships with no build step; these dependencies are used only to run the unit tests.",
  "type": "module",
  "scripts": {
    "test": "vitest run"
  },
  "devDependencies": {
    "jsdom": "^25.0.1",
    "vitest": "^2.1.8"
  }
}

import { defineConfig } from "vitest/config";

// The frontend is plain ES-module JavaScript that runs in the browser. We test it under jsdom and
// pin the timezone so locale/time assertions are deterministic across machines.
process.env.TZ = process.env.TZ || "UTC";

export default defineConfig({
  test: {
    environment: "jsdom",
    include: ["src/test/js/**/*.test.js"],
    setupFiles: ["src/test/js/setup.js"],
  },
});

// Global stubs for browser-only libraries loaded via CDN <script> tags in index.html.
// The frontend modules reference these as ambient globals.

// `marked` (markdown renderer) — stub with an identity-ish parser so rendering logic is testable.
globalThis.marked = {
  parse: (text) => (text == null ? "" : String(text)),
};

// `hljs` (syntax highlighter) — stub so calls are no-ops in tests.
globalThis.hljs = {
  highlightElement: () => {},
};

import { beforeEach, describe, expect, it } from "vitest";
import {
  state,
  escapeHtml,
  syntaxHighlight,
  formatTime,
  updateTranscriptFilter,
} from "../../main/resources/public/modules/utils.js";

beforeEach(() => {
  // Reset shared singleton state between tests.
  state.activeFilters = {
    userQueries: false,
    toolsCalled: false,
    outcomeErrors: false,
    modelResponses: false,
  };
  state.spansMultipleDays = false;
  document.body.innerHTML = "";
});

describe("escapeHtml", () => {
  it("escapes HTML-significant characters", () => {
    expect(escapeHtml('<a href="x">b & c\'d</a>')).toBe(
      "&lt;a href=&quot;x&quot;&gt;b &amp; c&#039;d&lt;/a&gt;"
    );
  });

  it("returns empty string for falsy input", () => {
    expect(escapeHtml("")).toBe("");
    expect(escapeHtml(null)).toBe("");
    expect(escapeHtml(undefined)).toBe("");
  });
});

describe("syntaxHighlight", () => {
  it("wraps each JSON token type in a classed span", () => {
    const html = syntaxHighlight({ a: 1, b: "x", c: true, d: null });
    expect(html).toContain('class="json-key"');
    expect(html).toContain('class="json-number"');
    expect(html).toContain('class="json-string"');
    expect(html).toContain('class="json-boolean"');
    expect(html).toContain('class="json-null"');
  });

  it("accepts a pre-stringified JSON string", () => {
    const html = syntaxHighlight('{"n": 42}');
    expect(html).toContain('<span class="json-number">42</span>');
  });
});

describe("formatTime", () => {
  it("returns empty string for missing input", () => {
    expect(formatTime("")).toBe("");
    expect(formatTime(null)).toBe("");
  });

  it("renders a 24-hour time for a single-day session", () => {
    const out = formatTime("2026-06-19T09:05:00Z");
    expect(out).toMatch(/^\d{2}:\d{2}$/);
  });

  it("prepends the date when the session spans multiple days", () => {
    state.spansMultipleDays = true;
    const out = formatTime("2026-06-19T09:05:00Z");
    // e.g. "Jun 19, 09:05"
    expect(out).toMatch(/[A-Za-z]{3}\s+\d{1,2},\s+\d{2}:\d{2}/);
  });
});

describe("updateTranscriptFilter", () => {
  function buildTranscript() {
    document.body.innerHTML = `
      <div class="sequence-wrapper">
        <div class="step-card" data-is-user="true" data-is-tool="false" data-is-error="false" data-is-model="false"></div>
        <div class="step-card" data-is-user="false" data-is-tool="true" data-is-error="false" data-is-model="false"></div>
      </div>
      <div class="sequence-wrapper">
        <div class="step-card" data-is-user="false" data-is-tool="false" data-is-error="true" data-is-model="false"></div>
      </div>
    `;
  }

  it("shows every card when no filter is active", () => {
    buildTranscript();
    updateTranscriptFilter();
    document
      .querySelectorAll(".step-card")
      .forEach((c) => expect(c.style.display).toBe("block"));
  });

  it("shows only matching cards and hides empty sequence wrappers", () => {
    buildTranscript();
    state.activeFilters.userQueries = true;
    updateTranscriptFilter();

    const cards = document.querySelectorAll(".step-card");
    expect(cards[0].style.display).toBe("block"); // user card
    expect(cards[1].style.display).toBe("none"); // tool card
    expect(cards[2].style.display).toBe("none"); // error card

    const wrappers = document.querySelectorAll(".sequence-wrapper");
    expect(wrappers[0].style.display).toBe("block"); // has the visible user card
    expect(wrappers[1].style.display).toBe("none"); // only the hidden error card
  });
});

import { beforeEach, describe, expect, it } from "vitest";
import { renderStats } from "../../main/resources/public/modules/stats.js";

beforeEach(() => {
  document.body.innerHTML = '<div id="session-stats-container" class="hidden"></div>';
});

function statValue(id) {
  return document
    .querySelector(`#${id} .stat-value`)
    .textContent.trim();
}

describe("renderStats", () => {
  it("hides the container when there are no steps", () => {
    renderStats([]);
    const container = document.getElementById("session-stats-container");
    expect(container.classList.contains("hidden")).toBe(true);
  });

  it("counts user queries, tool calls, model responses and errors", () => {
    const steps = [
      { type: "USER_INPUT", content: "hi", created_at: "2026-06-19T10:00:00Z" },
      {
        source: "MODEL",
        type: "PLANNER_RESPONSE",
        content: "here is the answer",
        created_at: "2026-06-19T10:00:05Z",
      },
      {
        source: "MODEL",
        type: "PLANNER_RESPONSE",
        tool_calls: [{ name: "edit" }],
        created_at: "2026-06-19T10:00:10Z",
      },
      {
        type: "ERROR_MESSAGE",
        status: "ERROR",
        content: "boom",
        created_at: "2026-06-19T10:00:20Z",
      },
    ];

    renderStats(steps);

    expect(statValue("user-queries-stat-card")).toBe("1");
    expect(statValue("tools-stat-card")).toBe("1");
    expect(statValue("model-responses-stat-card")).toBe("1");
    expect(document.getElementById("session-stats-container").classList.contains("hidden")).toBe(
      false
    );
    // OUTCOME card reflects the error.
    expect(statValue("errors-stat-card")).toBe("Issues Detected");
  });

  it("reports success when there are no errors", () => {
    const steps = [
      { type: "USER_INPUT", content: "hi", created_at: "2026-06-19T10:00:00Z" },
    ];
    renderStats(steps);
    expect(statValue("errors-stat-card")).toBe("Succeeded");
  });

  it("counts tool steps that use a tool-like type without a tool_calls array", () => {
    const steps = [
      { type: "USER_INPUT", content: "hi", created_at: "2026-06-19T10:00:00Z" },
      { type: "VIEW_FILE", content: "...", created_at: "2026-06-19T10:00:01Z" },
      { type: "RUN_COMMAND", content: "...", created_at: "2026-06-19T10:00:02Z" },
    ];
