// Playwright global setup: seed the fixture brain directory that the server reads via -Duser.home,
// and fail early with a helpful message if the runnable jar hasn't been built yet.

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { seedFixtures } from "./fixtures.mjs";

const projectRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");

export default function globalSetup() {
  const home = path.join(projectRoot, "build", "e2e-home");
  seedFixtures(home);

  const libs = path.join(projectRoot, "build", "libs");
  const hasJar =
    fs.existsSync(libs) && fs.readdirSync(libs).some((f) => f.endsWith("-all.jar"));
  if (!hasJar) {
    throw new Error(
      "No runnable jar found in build/libs (expected *-all.jar).\n" +
        "Build it first, e.g.:  mise exec -- ./gradlew shadowJar -x test"
    );
  }
}

import { defineConfig, devices } from "@playwright/test";
import path from "node:path";
import { fileURLToPath } from "node:url";

const projectRoot = path.dirname(fileURLToPath(import.meta.url));
const PORT = 8099;
const E2E_HOME = path.join(projectRoot, "build", "e2e-home");

// Launch the prebuilt fat jar with user.home pointed at the seeded fixtures. A dummy GEMINI_API_KEY
// lets the cached-analysis path run without contacting the real LLM (the cache lookup is gated
// behind the key check). The single quotes keep the glob from being expanded before sh runs it.
const serverCommand =
  `sh -c 'java -Duser.home="${E2E_HOME}" -Dmicronaut.server.port=${PORT} ` +
  `-jar $(ls build/libs/*-all.jar | head -1)'`;

export default defineConfig({
