import { test, expect } from "@playwright/test";

test.describe("session browsing", () => {
  test("lists the seeded sessions", async ({ page }) => {
    await page.goto("/");
    const items = page.locator("#conversations-list .conv-item");
    await expect(items).toHaveCount(2);
    await expect(page.locator(".conv-item", { hasText: "Fix the parser bug" })).toBeVisible();
    await expect(page.locator(".conv-item", { hasText: "Add dark mode" })).toBeVisible();
  });

  test("search filters the list", async ({ page }) => {
    await page.goto("/");
    await expect(page.locator("#conversations-list .conv-item")).toHaveCount(2);
    await page.fill("#conversation-search", "parser");
    await expect(page.locator("#conversations-list .conv-item")).toHaveCount(1);
    await expect(page.locator("#conversations-list .conv-item")).toContainText(
      "Fix the parser bug"
    );
  });

  test("sort toggle reverses the order (newest-first by default)", async ({ page }) => {
    await page.goto("/");
    await expect(page.locator("#conversations-list .conv-item").first()).toContainText(
      "Add dark mode"
    );
    await page.click("#sort-conversations-btn");
    await expect(page.locator("#conversations-list .conv-item").first()).toContainText(
      "Fix the parser bug"
    );
  });

  test("switching flavor loads that flavor's sessions", async ({ page }) => {
    await page.goto("/");
    await expect(page.locator("#conversations-list .conv-item")).toHaveCount(2);
    await page.selectOption("#flavor-select", "antigravity-ide");
    await expect(page.locator("#conversations-list .conv-item")).toHaveCount(1);
    await expect(page.locator("#conversations-list .conv-item")).toContainText(
      "IDE refactor session"
    );
  });
});

import { test, expect } from "@playwright/test";

async function openParserSession(page) {
  await page.goto("/");
  await page.click('.conv-item:has-text("Fix the parser bug")');
}

test.describe("transcript & stats", () => {
  test("selecting a session renders its transcript", async ({ page }) => {
    await openParserSession(page);
    const tc = page.locator("#transcript-container");
    await expect(tc.locator(".sequence-wrapper").first()).toBeVisible();
    await expect(tc.locator(".step-card")).toHaveCount(4);
    await expect(page.locator("#current-session-title")).toContainText("Fix the parser bug");
  });

  test("renders accurate session statistics", async ({ page }) => {
    await openParserSession(page);
    await expect(page.locator("#session-stats-container")).toBeVisible();
    await expect(page.locator("#user-queries-stat-card .stat-value")).toHaveText("1");
    await expect(page.locator("#tools-stat-card .stat-value")).toHaveText("2");
    await expect(page.locator("#model-responses-stat-card .stat-value")).toHaveText("1");
    await expect(page.locator("#errors-stat-card .stat-value")).toContainText("Issues Detected");
  });

  test("the tools stat card reveals the tool distribution chart", async ({ page }) => {
    await openParserSession(page);
    await page.click("#tools-stat-card");
    const chart = page.locator("#tools-chart");
    await expect(chart).toBeVisible();
    await expect(chart).toContainText("edit_file");
    await expect(chart).toContainText("run_command");
  });

  test("user-query filter hides non-user cards", async ({ page }) => {
    await openParserSession(page);
    await page.click("#user-queries-stat-card");
    // Only the user card stays displayed.
    const visibleCards = page.locator("#transcript-container .step-card:visible");
    await expect(visibleCards).toHaveCount(1);
  });
});

import { test, expect } from "@playwright/test";

test.describe("file preview modal", () => {
  test("clicking a file link opens, renders, and closes the modal", async ({ page }) => {
    await page.goto("/");
    await page.click('.conv-item:has-text("Fix the parser bug")');

    // The file link lives in a collapsed step body — expand the card that contains it.
    const linkCard = page.locator("#transcript-container .step-card", {
      has: page.locator('a[href^="file://"]'),
    });
    await linkCard.locator(".step-header").first().click();

    const link = linkCard.locator('a[href^="file://"]').first();
    await expect(link).toBeVisible();
    await link.click();

    const modal = page.locator("#file-modal");
    await expect(modal).toBeVisible();
    await expect(page.locator("#file-modal-title")).toContainText("config.txt");
    await expect(page.locator("#file-modal-content")).toContainText("parser.mode = strict");

    await page.keyboard.press("Escape");
    await expect(modal).toBeHidden();
  });
});

import { test, expect } from "@playwright/test";

test.describe("AI analysis", () => {
  test("auto-loads the cached analysis for a session", async ({ page }) => {
    await page.goto("/");
    await page.click('.conv-item:has-text("Fix the parser bug")');

    const ai = page.locator("#ai-summary-text");
    await expect(ai).toContainText("null-pointer bug in the parser");
    await expect(ai).toContainText("Conversation Flow");
    await expect(ai).toContainText("Issues & Circumventions");
    await expect(ai).toContainText("Added a null check");
    await expect(ai).toContainText("Future Recommendations");
  });

  test("recompute fetches and renders a fresh analysis", async ({ page }) => {
    // Stub the LLM-backed endpoints so recompute never hits the real model.
    await page.route("**/api/analysis/conversations/*/summarize**", (route) =>
      route.fulfill({
        json: {
          shortTitle: "Recomputed",
          summary: "Freshly recomputed summary text",
          flow: ["new step"],
          agentActions: [],
          issues: [],
          recommendations: [],
        },
      })
    );
    await page.route("**/api/analysis/conversations/*/progress**", (route) =>
      route.fulfill({ json: { phase: "Done", progress: 100 } })
    );

    await page.goto("/");
    await page.click('.conv-item:has-text("Fix the parser bug")');
    await page.click("#summarize-btn");

    await expect(page.locator("#ai-summary-text")).toContainText(
      "Freshly recomputed summary text"
    );
  });
});

import { test, expect } from "@playwright/test";

test.describe("layout & navigation chrome", () => {
  test("toggling the sidebar collapses and expands it", async ({ page }) => {
    await page.goto("/");
    const sidebar = page.locator(".sidebar");
    await expect(sidebar).not.toHaveClass(/collapsed/);
    await page.click("#sidebar-toggle-btn");
    await expect(sidebar).toHaveClass(/collapsed/);
    await page.click("#sidebar-toggle-btn");
    await expect(sidebar).not.toHaveClass(/collapsed/);
  });

  test("dragging the resizer changes the sidebar width", async ({ page }) => {
    await page.goto("/");
    const resizer = page.locator("#sidebar-resizer");
    const box = await resizer.boundingBox();
    await page.mouse.move(box.x + box.width / 2, box.y + box.height / 2);
    await page.mouse.down();
    await page.mouse.move(360, box.y + box.height / 2, { steps: 8 });
    await page.mouse.up();

    const width = await page.evaluate(() =>
      getComputedStyle(document.documentElement).getPropertyValue("--sidebar-width").trim()
    );
    const px = parseInt(width, 10);
    expect(px).toBeGreaterThanOrEqual(200);
    expect(px).toBeLessThanOrEqual(800);
  });

  test("the timeline scrubber thumb tracks transcript scrolling", async ({ page }) => {
    await page.setViewportSize({ width: 1200, height: 320 });
    await page.goto("/");
    await page.click('.conv-item:has-text("Fix the parser bug")');

    // Expand every card so the transcript overflows its container and becomes scrollable.
    for (const header of await page.locator("#transcript-container .step-header").all()) {
      await header.click();
    }

    const tc = page.locator("#transcript-container");
    const scrollable = await tc.evaluate((el) => el.scrollHeight > el.clientHeight + 5);
    test.skip(!scrollable, "transcript does not overflow in this viewport");

    const thumb = page.locator("#timeline-thumb");
    const before = await thumb.evaluate((el) => el.style.top || "0px");
    await tc.evaluate((el) => {
      el.scrollTop = el.scrollHeight;
      el.dispatchEvent(new Event("scroll"));
    });
    await expect
      .poll(async () => thumb.evaluate((el) => el.style.top || "0px"))
      .not.toBe(before);
  });
});

