package io.github.glaforge.agybrainviz;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import jakarta.inject.Inject;
import jakarta.inject.Singleton;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.stream.Stream;

/**
 * Builds the cross-session {@link InsightsReport} for a source by collecting each session's
 * normalized steps (and any cached analysis) and handing them to {@link FleetInsights}. Antigravity
 * is read from {@code ~/.gemini/<flavor>/brain}; other sources go through their {@link SessionSource}.
 *
 * <p>The scan is capped at the most recent {@link #MAX_SESSIONS} sessions so the endpoint stays
 * responsive even for very large session histories; {@link InsightsReport#sessionCount()} still
 * reports the true total.
 */
@Singleton
public class InsightsService {

    static final int MAX_SESSIONS = 150;

    private static final ObjectMapper MAPPER = new ObjectMapper();

    private final List<SessionSource> sources;

    @Inject
    public InsightsService(List<SessionSource> sources) {
        this.sources = sources;
    }

    public InsightsReport forFlavor(String flavor) throws IOException {
        Optional<SessionSource> source = sources
            .stream()
            .filter(s -> s.handles(flavor))
            .findFirst();
        return source.isPresent() ? fromSource(flavor, source.get()) : fromAntigravity(flavor);
    }

    private InsightsReport fromSource(String flavor, SessionSource source) throws IOException {
        List<Map<String, String>> conversations = source.listConversations();
        List<FleetInsights.Session> sessions = new ArrayList<>();
        for (Map<String, String> info : conversations) {
            if (sessions.size() >= MAX_SESSIONS) break;
            String id = info.get("id");
            List<JsonNode> steps = parseArray(source.transcriptJson(id));
            JsonNode summary = source.cachedSummary(id).map(this::parseJson).orElse(null);
            sessions.add(new FleetInsights.Session(steps, summary));
        }
        return FleetInsights.aggregate(flavor, conversations.size(), sessions);
    }

    private InsightsReport fromAntigravity(String flavor) throws IOException {
        String dirName = (flavor == null || flavor.isEmpty()) ? "antigravity-cli" : flavor;
        Path brain = Paths.get(System.getProperty("user.home"), ".gemini", dirName, "brain");
        if (!Files.isDirectory(brain)) {
            return FleetInsights.aggregate(flavor, 0, List.of());
        }

        List<Path> dirs;
        try (Stream<Path> paths = Files.list(brain)) {
            dirs = paths
                .filter(Files::isDirectory)
                .filter(d -> transcriptOf(d) != null)
                .sorted(Comparator.comparingLong(this::lastModified).reversed())
                .toList();
        }

        List<FleetInsights.Session> sessions = new ArrayList<>();
        for (Path dir : dirs) {
            if (sessions.size() >= MAX_SESSIONS) break;
            Path logs = dir.resolve(".system_generated").resolve("logs");
            List<JsonNode> steps = parseLines(Files.readAllLines(transcriptOf(dir)));
            JsonNode summary = readJson(logs.resolve("summary.json"));
            sessions.add(new FleetInsights.Session(steps, summary));
        }
        return FleetInsights.aggregate(flavor, dirs.size(), sessions);
    }

    private Path transcriptOf(Path sessionDir) {
        Path t = sessionDir.resolve(".system_generated").resolve("logs").resolve("transcript.jsonl");
        try {
            return (Files.exists(t) && Files.size(t) > 0) ? t : null;
        } catch (IOException e) {
            return null;
        }
    }

    private long lastModified(Path sessionDir) {
        try {
            return Files.getLastModifiedTime(transcriptOf(sessionDir)).toMillis();
        } catch (Exception e) {
            return 0L;
        }
    }

    private List<JsonNode> parseArray(String jsonArray) {
        List<JsonNode> steps = new ArrayList<>();
        try {
            JsonNode arr = MAPPER.readTree(jsonArray);
            if (arr.isArray()) arr.forEach(steps::add);
        } catch (Exception e) {
            // ignore malformed transcript
        }
        return steps;
    }

    private List<JsonNode> parseLines(List<String> lines) {
        List<JsonNode> steps = new ArrayList<>();
        for (String line : lines) {
            if (line == null || line.isBlank()) continue;
            try {
                steps.add(MAPPER.readTree(line));
            } catch (Exception e) {
                // skip malformed line
            }
        }
        return steps;
    }

    private JsonNode parseJson(String json) {
        try {
            return MAPPER.readTree(json);
        } catch (Exception e) {
            return null;
        }
    }

    private JsonNode readJson(Path path) {
        try {
            return Files.exists(path) ? MAPPER.readTree(Files.readString(path)) : null;
        } catch (Exception e) {
            return null;
        }
    }
}

