16	package io.github.glaforge.agybrainviz;
17	
18	import com.fasterxml.jackson.databind.JsonNode;
19	import java.time.Instant;
20	import java.util.ArrayList;
21	import java.util.LinkedHashMap;
22	import java.util.List;
23	import java.util.Map;
24	
25	/**
26	 * Pure aggregation of many sessions' normalized steps (plus any cached AI analysis) into an
27	 * {@link InsightsReport}. Works on the shared step schema, so it is source-agnostic and fully
28	 * unit-testable without any I/O.
29	 */
30	final class FleetInsights {
31	
32	    private FleetInsights() {}
33	
34	    private static final int TOP_N = 10;
35	
36	    /** One session's input: its normalized timeline steps and (optionally) its cached analysis JSON. */
37	    record Session(List<JsonNode> steps, JsonNode cachedSummary) {}
38	
39	    static InsightsReport aggregate(String flavor, int totalSessionCount, List<Session> sessions) {
40	        Map<String, Integer> toolFreq = new LinkedHashMap<>();
41	        Map<String, Integer> errorFreq = new LinkedHashMap<>();
42	        Map<String, Integer> recFreq = new LinkedHashMap<>();
43	        Map<String, Integer> issueFreq = new LinkedHashMap<>();
44	
45	        int toolCallTotal = 0;
46	        int sessionsWithErrors = 0;
47	        int analyzedSessions = 0;
48	        long totalToolCalls = 0;
49	        List<Double> durations = new ArrayList<>();
50	
51	        for (Session session : sessions) {
52	            int sessionTools = 0;
53	            boolean sessionHasError = false;
54	            long minTs = Long.MAX_VALUE;
55	            long maxTs = Long.MIN_VALUE;
56	
57	            for (JsonNode step : session.steps()) {
58	                Long ts = epochMillis(step.path("created_at").asText(""));
59	                if (ts != null) {
60	                    minTs = Math.min(minTs, ts);
61	                    maxTs = Math.max(maxTs, ts);
62	                }
63	
64	                JsonNode toolCalls = step.path("tool_calls");
65	                if (toolCalls.isArray()) {
66	                    for (JsonNode tool : toolCalls) {
67	                        String name = tool.path("name").asText("unknown");
68	                        toolFreq.merge(name, 1, Integer::sum);
69	                        sessionTools++;
70	                        toolCallTotal++;
71	                    }
72	                }
73	
74	                if (isError(step)) {
75	                    sessionHasError = true;
76	                    errorFreq.merge(errorKey(step), 1, Integer::sum);
77	                }
78	            }
79	
80	            totalToolCalls += sessionTools;
81	            if (sessionHasError) sessionsWithErrors++;
82	            // Zero-span sessions (single step / identical timestamps) are excluded from the average
83	            // rather than counted as 0s, so trivial sessions don't drag the mean toward zero.
84	            if (maxTs > minTs) durations.add((maxTs - minTs) / 1000.0);
85	
86	            JsonNode summary = session.cachedSummary();
87	            if (summary != null && !summary.isMissingNode() && !summary.isNull()) {
88	                analyzedSessions++;
89	                for (JsonNode rec : summary.path("recommendations")) {
90	                    String text = clean(rec.asText(""));
91	                    if (!text.isBlank()) recFreq.merge(text, 1, Integer::sum);
92	                }
93	                for (JsonNode issue : summary.path("issues")) {
94	                    String text = clean(issue.path("error").asText(""));
95	                    if (!text.isBlank()) issueFreq.merge(text, 1, Integer::sum);
96	                }
97	            }
98	        }
99	
100	        int sampled = sessions.size();
101	        double avgTools = sampled == 0 ? 0.0 : (double) totalToolCalls / sampled;
102	        double avgDuration = durations.isEmpty()
103	            ? 0.0
104	            : durations.stream().mapToDouble(Double::doubleValue).average().orElse(0.0);
105	
106	        return new InsightsReport(
107	            flavor,
108	            totalSessionCount,
109	            sampled,
110	            analyzedSessions,
111	            toolCallTotal,
112	            sessionsWithErrors,
113	            sampled - sessionsWithErrors,
114	            round1(avgTools),
115	            round1(avgDuration),
116	            top(toolFreq),
117	            top(errorFreq),
118	            top(recFreq),
119	            top(issueFreq)
120	        );
121	    }
122	
123	    private static boolean isError(JsonNode step) {
124	        String status = step.path("status").asText("");
125	        String type = step.path("type").asText("");
126	        String content = step.path("content").asText("");
127	        return (
128	            "ERROR".equals(status) ||
129	            "ERROR_MESSAGE".equals(type) ||
130	            ("RUN_COMMAND".equals(type) && content.contains("The command failed"))
131	        );
132	    }
133	
134	    private static String errorKey(JsonNode step) {
135	        if ("RUN_COMMAND".equals(step.path("type").asText(""))) {
136	            return "Command execution failed";
137	        }
138	        String source = step.has("error")
139	            ? step.path("error").asText("")
140	            : step.path("content").asText("");
141	        for (String line : source.split("\n")) {
142	            String trimmed = line.trim();
143	            if (
144	                trimmed.isEmpty() ||
145	                trimmed.startsWith("Created At:") ||
146	                trimmed.startsWith("Completed At:")
147	            ) {
148	                continue;
149	            }
150	            String prefix = "Encountered error in step execution: ";
151	            if (trimmed.startsWith(prefix)) trimmed = trimmed.substring(prefix.length()).trim();
152	            return truncate(trimmed, 100);
153	        }
154	        return "Unknown error";
155	    }
156	
157	    private static Long epochMillis(String iso) {
158	        if (iso == null || iso.isBlank()) return null;
159	        try {
160	            return Instant.parse(iso).toEpochMilli();
161	        } catch (Exception e) {
162	            return null;
163	        }
164	    }
165	
166	    private static String clean(String text) {
167	        return truncate(text == null ? "" : text.strip(), 200);
168	    }
169	
170	    private static String truncate(String text, int max) {
171	        return text.length() > max ? text.substring(0, max) : text;
172	    }
173	
174	    private static double round1(double value) {
175	        return Math.round(value * 10.0) / 10.0;
176	    }
177	
178	    private static List<NameCount> top(Map<String, Integer> freq) {
179	        return freq
180	            .entrySet()
181	            .stream()
182	            .sorted(Map.Entry.<String, Integer>comparingByValue().reversed())
183	            .limit(TOP_N)
184	            .map(e -> new NameCount(e.getKey(), e.getValue()))
185	            .toList();
186	    }
187	}
