32	
33	/**
34	 * Builds the cross-session {@link InsightsReport} for a source by collecting each session's
35	 * normalized steps (and any cached analysis) and handing them to {@link FleetInsights}. Antigravity
36	 * is read from {@code ~/.gemini/<flavor>/brain}; other sources go through their {@link SessionSource}.
37	 *
38	 * <p>The scan is capped at the most recent {@link #MAX_SESSIONS} sessions so the endpoint stays
39	 * responsive even for very large session histories; {@link InsightsReport#sessionCount()} still
40	 * reports the true total.
41	 */
42	@Singleton
43	public class InsightsService {
44	
45	    static final int MAX_SESSIONS = 150;
46	
47	    private static final ObjectMapper MAPPER = new ObjectMapper();
48	
49	    private final List<SessionSource> sources;
50	
51	    @Inject
52	    public InsightsService(List<SessionSource> sources) {
53	        this.sources = sources;
54	    }
55	
56	    public InsightsReport forFlavor(String flavor) throws IOException {
57	        Optional<SessionSource> source = sources
58	            .stream()
59	            .filter(s -> s.handles(flavor))
60	            .findFirst();
61	        return source.isPresent() ? fromSource(flavor, source.get()) : fromAntigravity(flavor);
62	    }
63	
64	    private InsightsReport fromSource(String flavor, SessionSource source) throws IOException {
65	        List<Map<String, String>> conversations = source.listConversations();
66	        List<FleetInsights.Session> sessions = new ArrayList<>();
67	        for (Map<String, String> info : conversations) {
68	            if (sessions.size() >= MAX_SESSIONS) break;
69	            String id = info.get("id");
70	            List<JsonNode> steps = parseArray(source.transcriptJson(id));
71	            JsonNode summary = source.cachedSummary(id).map(this::parseJson).orElse(null);
72	            sessions.add(new FleetInsights.Session(steps, summary));
73	        }
74	        return FleetInsights.aggregate(flavor, conversations.size(), sessions);
75	    }
76	
77	    private InsightsReport fromAntigravity(String flavor) throws IOException {
78	        String dirName = (flavor == null || flavor.isEmpty()) ? "antigravity-cli" : flavor;
79	        Path brain = Paths.get(System.getProperty("user.home"), ".gemini", dirName, "brain");
80	        if (!Files.isDirectory(brain)) {
81	            return FleetInsights.aggregate(flavor, 0, List.of());
82	        }
83	
84	        List<Path> dirs;
85	        try (Stream<Path> paths = Files.list(brain)) {
86	            dirs =
87	                paths
88	                    .filter(Files::isDirectory)
89	                    .filter(d -> transcriptOf(d) != null)
90	                    .sorted(Comparator.comparingLong(this::lastModified).reversed())
91	                    .toList();
92	        }
93	
94	        List<FleetInsights.Session> sessions = new ArrayList<>();
95	        for (Path dir : dirs) {
96	            if (sessions.size() >= MAX_SESSIONS) break;
97	            Path transcript = readableTranscript(dir);
98	            if (transcript == null) continue;
99	            try {
100	                List<JsonNode> steps = parseLines(Files.readAllLines(transcript));
101	                Path logs = dir.resolve(".system_generated").resolve("logs");
102	                JsonNode summary = readJson(logs.resolve("summary.json"));
103	                sessions.add(new FleetInsights.Session(steps, summary));
104	            } catch (IOException e) {
105	                // A session may be deleted/rotated mid-scan; skip it rather than failing the report.
106	            }
107	        }
108	        return FleetInsights.aggregate(flavor, dirs.size(), sessions);
109	    }
110	
111	    // A session is listed (and sorted) by its transcript.jsonl, mirroring BrainController.list.
112	    private Path transcriptOf(Path sessionDir) {
113	        return nonEmpty(
114	            sessionDir.resolve(".system_generated").resolve("logs").resolve("transcript.jsonl")
115	        );
116	    }
117	
118	    // For reading, prefer transcript_full.jsonl when present, mirroring BrainController.getTranscript,
119	    // so the insights counts match the rendered timeline.
120	    private Path readableTranscript(Path sessionDir) {
121	        Path logs = sessionDir.resolve(".system_generated").resolve("logs");
122	        Path full = nonEmpty(logs.resolve("transcript_full.jsonl"));
123	        return full != null ? full : nonEmpty(logs.resolve("transcript.jsonl"));
124	    }
125	
126	    private Path nonEmpty(Path file) {
127	        try {
128	            return (Files.exists(file) && Files.size(file) > 0) ? file : null;
129	        } catch (IOException e) {
130	            return null;
131	        }
132	    }
133	
134	    private long lastModified(Path sessionDir) {
135	        Path transcript = transcriptOf(sessionDir);
136	        if (transcript == null) return 0L;
137	        try {
138	            return Files.getLastModifiedTime(transcript).toMillis();
139	        } catch (Exception e) {
140	            return 0L;
141	        }
142	    }
143	
144	    private List<JsonNode> parseArray(String jsonArray) {
145	        List<JsonNode> steps = new ArrayList<>();
146	        try {
147	            JsonNode arr = MAPPER.readTree(jsonArray);
148	            if (arr.isArray()) arr.forEach(steps::add);
149	        } catch (Exception e) {
150	            // ignore malformed transcript
151	        }
152	        return steps;
153	    }
154	
155	    private List<JsonNode> parseLines(List<String> lines) {
156	        List<JsonNode> steps = new ArrayList<>();
157	        for (String line : lines) {
158	            if (line == null || line.isBlank()) continue;
159	            try {
160	                steps.add(MAPPER.readTree(line));
161	            } catch (Exception e) {
162	                // skip malformed line
163	            }
164	        }
165	        return steps;
166	    }
167	
168	    private JsonNode parseJson(String json) {
169	        try {
170	            return MAPPER.readTree(json);
171	        } catch (Exception e) {
172	            return null;
173	        }
174	    }
175	
176	    private JsonNode readJson(Path path) {
177	        try {
178	            return Files.exists(path) ? MAPPER.readTree(Files.readString(path)) : null;
179	        } catch (Exception e) {
180	            return null;
181	        }
182	    }
183	}
