16	package io.github.glaforge.agybrainviz;
17	
18	import com.fasterxml.jackson.databind.ObjectMapper;
19	import io.micronaut.http.annotation.Controller;
20	import io.micronaut.http.annotation.Get;
21	import io.micronaut.http.annotation.PathVariable;
22	import io.micronaut.http.annotation.QueryValue;
23	import io.micronaut.scheduling.TaskExecutors;
24	import io.micronaut.scheduling.annotation.ExecuteOn;
25	import io.micronaut.serde.annotation.Serdeable;
26	import jakarta.inject.Inject;
27	import jakarta.inject.Named;
28	import java.io.IOException;
29	import java.nio.file.Files;
30	import java.nio.file.Path;
31	import java.nio.file.Paths;
32	import java.util.ArrayList;
33	import java.util.List;
34	import java.util.Map;
35	import java.util.Optional;
36	import java.util.concurrent.ConcurrentHashMap;
37	import java.util.concurrent.ExecutorService;
38	import java.util.concurrent.Future;
39	import java.util.concurrent.Semaphore;
40	import java.util.concurrent.atomic.AtomicBoolean;
41	import java.util.concurrent.atomic.AtomicInteger;
42	import java.util.function.ToIntFunction;
43	
44	@Controller("/api/analysis")
45	public class AnalysisController {
46	
47	    private Path getBrainPath(String flavor) {
48	        if (flavor == null || flavor.isEmpty()) flavor = "antigravity-cli";
49	        return Paths.get(System.getProperty("user.home"), ".gemini", flavor, "brain");
50	    }
51	
52	    private static final int MAX_TOKENS_PER_CHUNK = 100_000;
53	    private static final Map<String, ProgressState> progressMap = new ConcurrentHashMap<>();
54	
55	    @Serdeable
56	    public record ProgressState(int progress, String phase) {}
57	
58	    @Get(value = "/conversations/{id}/progress", produces = "application/json")
59	    public ProgressResponse getProgress(@PathVariable String id) {
60	        ProgressState state = progressMap.get(id);
61	        if (state == null) {
62	            return new ProgressResponse("", -1);
63	        }
64	        return new ProgressResponse(state.phase(), state.progress());
65	    }
66	
67	    @Serdeable
68	    public record ProgressResponse(String phase, int progress) {}
69	
70	    private final AnalyzerService analyzerService;
71	    private final ExecutorService executor;
72	    private final AiConfig aiConfig;
73	    private final TokenCounter tokenCounter;
74	    private final List<SessionSource> sessionSources;
75	
76	    @Inject
77	    public AnalysisController(
78	        AnalyzerService analyzerService,
79	        @Named(TaskExecutors.IO) ExecutorService executor,
80	        AiConfig aiConfig,
81	        TokenCounter tokenCounter,
82	        List<SessionSource> sessionSources
83	    ) {
84	        this.analyzerService = analyzerService;
85	        this.executor = executor;
86	        this.aiConfig = aiConfig;
87	        this.tokenCounter = tokenCounter;
88	        this.sessionSources = sessionSources;
89	    }
90	
91	    private Optional<SessionSource> sourceFor(String flavor) {
92	        return sessionSources.stream().filter(s -> s.handles(flavor)).findFirst();
93	    }
94	
95	    private static final Map<String, Object> runningTasks = new ConcurrentHashMap<>();
96	
97	    @ExecuteOn(TaskExecutors.IO)
98	    @Get(value = "/conversations/{id}/summarize", produces = "application/json")
99	    public String summarizeConversation(
100	        @PathVariable String id,
101	        @QueryValue Optional<Boolean> force,
102	        @QueryValue Optional<String> flavor
103	    ) throws IOException {
104	        if (!aiConfig.isConfigured()) {
105	            // Serialize via Jackson so the message is always valid JSON, regardless of its content.
106	            return new ObjectMapper()
107	                .writeValueAsString(Map.of("summary", aiConfig.notConfiguredMessage()));
108	        }
109	
110	        if (runningTasks.putIfAbsent(id, new Object()) != null) {
111	            return "{\"summary\": \"Analysis is already running in the background for this conversation. Please wait a moment and refresh.\"}";
112	        }
113	
114	        try {
115	            Optional<SessionSource> source = sourceFor(flavor.orElse(""));
116	            boolean external = source.isPresent();
117	            boolean forceRecompute = force.orElse(false);
118	
119	            // Antigravity caches the summary inside the agent's own brain dir; external sources
120	            // (Codex, Claude Code) cache via their SessionSource. Antigravity paths are resolved up
121	            // front; for external sources they stay null.
122	            Path logsDir = external
123	                ? null
124	                : getBrainPath(flavor.orElse("antigravity-cli"))
125	                    .resolve(id)
126	                    .resolve(".system_generated")
127	                    .resolve("logs");
128	            Path transcriptPath = external ? null : logsDir.resolve("transcript.jsonl");
129	            Path summaryJsonPath = external ? null : logsDir.resolve("summary.json");
130	            Path shortTitlePath = external ? null : logsDir.resolve("short_title.txt");
131	
132	            boolean exists = external
133	                ? source.get().sessionExists(id)
134	                : Files.exists(transcriptPath);
135	            if (!exists) {
136	                return "{\"summary\": \"No transcript found.\"}";
137	            }
138	
139	            if (!forceRecompute) {
140	                Optional<String> cached = external
141	                    ? source.get().cachedSummary(id)
142	                    : (
143	                        Files.exists(summaryJsonPath)
144	                            ? Optional.of(Files.readString(summaryJsonPath))
145	                            : Optional.empty()
146	                    );
147	                if (cached.isPresent()) {
148	                    return cached.get();
149	                }
150	            } else if (external) {
151	                source.get().deleteCache(id);
152	            } else {
153	                Files.deleteIfExists(summaryJsonPath);
154	            }
155	
156	            ObjectMapper mapper = new ObjectMapper();
157	            AnalysisResponse responseObj = null;
158	            boolean consolidationFellBack = false;
159	
160	            try {
161	                List<List<String>> sequences = external
162	                    ? source.get().analysisSequences(id)
163	                    : TranscriptParser.parseSequences(Files.readAllLines(transcriptPath));
164	
165	                ToIntFunction<String> tokenFn = tokenCounter::estimate;
166	
167	                progressMap.put(id, new ProgressState(5, "Estimating Tokens & Chunking...")); // Phase 1: Estimating
168	
169	                List<String> combinedLines = new ArrayList<>();
170	                for (List<String> seq : sequences) {
171	                    combinedLines.addAll(seq);
172	                }
173	                List<List<String>> optimalChunks = new ArrayList<>();
174	                TranscriptParser.splitIntoSafeChunks(
175	                    combinedLines,
176	                    tokenFn,
177	                    MAX_TOKENS_PER_CHUNK,
178	                    optimalChunks
179	                );
180	
181	                System.out.println(
182	                    "Total optimal chunks to process in parallel: " + optimalChunks.size()
183	                );
184	
185	                progressMap.put(id, new ProgressState(0, "Starting chunk processing...")); // start at 0%
186	
187	                List<Future<AnalysisResponse>> futures = new ArrayList<>();
188	                AtomicInteger completed = new AtomicInteger(0);
189	
190	                // Limit to 20 concurrent LLM requests, as we have drastically reduced chunk count
191	                Semaphore rateLimitSemaphore = new Semaphore(20);
192	
193	                for (List<String> chunkLines : optimalChunks) {
194	                    futures.add(
195	                        executor.submit(() -> {
196	                            try {
197	                                rateLimitSemaphore.acquire();
198	                            } catch (InterruptedException e) {
199	                                Thread.currentThread().interrupt();
200	                                return null;
201	                            }
202	
203	                            try {
204	                                String chunk = String.join("\n", chunkLines);
205	                                AnalysisResponse seqResponse = null;
206	                                try {
207	                                    seqResponse = analyzerService.analyze(chunk);
208	                                } catch (Exception e) {
209	                                    System.err.println(
210	                                        "Failed to parse chunk from LLM: " + e.getMessage()
211	                                    );
212	                                    e.printStackTrace();
213	                                    // Ignore unparseable chunk
214	                                }
215	
216	                                int comp = completed.incrementAndGet();
217	                                // Scale parallel processing to 90% of the total progress
218	                                int pct = (int) Math.round((comp * 90.0) / optimalChunks.size());
219	                                String phaseMsg =
220	                                    "Processing chunk " +
221	                                    comp +
222	                                    " of " +
223	                                    optimalChunks.size() +
224	                                    "...";
225	
226	                                // Prevent progress moving backwards if futures finish out of order
227	                                progressMap.compute(
228	                                    id,
229	                                    (k, v) -> {
230	                                        if (v == null || pct > v.progress()) {
231	                                            return new ProgressState(pct, phaseMsg);
232	                                        }
233	                                        return v;
234	                                    }
235	                                );
236	
237	                                return seqResponse;
238	                            } finally {
239	                                rateLimitSemaphore.release();
240	                            }
241	                        })
242	                    );
243	                }
244	
245	                List<AnalysisResponse> seqResponses = new ArrayList<>();
246	                for (Future<AnalysisResponse> f : futures) {
247	                    AnalysisResponse r = f.get();
248	                    if (r != null) seqResponses.add(r);
249	                }
250	
251	                if (seqResponses.isEmpty()) {
252	                    // Distinguish "nothing to analyze" from "the model failed for every chunk".
253	                    String msg = optimalChunks.isEmpty()
254	                        ? "No transcript lines found."
255	                        : "Analysis could not be generated: the model did not return a result for any part of this conversation. Please try again.";
256	                    return mapper.writeValueAsString(Map.of("summary", msg));
257	                } else if (seqResponses.size() == 1) {
258	                    responseObj = seqResponses.get(0);
259	                } else {
260	                    progressMap.put(id, new ProgressState(90, "Consolidating final analysis..."));
261	
262	                    // Keep the progress bar moving smoothly during the long final LLM consolidation
263	                    AtomicBoolean consolidationDone = new AtomicBoolean(false);
264	                    Future<?> fakeProgress = executor.submit(() -> {
265	                        int p = 90;
266	                        while (!consolidationDone.get() && p < 99) {
267	                            try {
268	                                Thread.sleep(2000);
269	                            } catch (InterruptedException e) {
270	                                break;
271	                            }
272	                            if (!consolidationDone.get()) {
273	                                int nextP = p + 1;
274	                                progressMap.put(
275	                                    id,
276	                                    new ProgressState(nextP, "Consolidating final analysis...")
277	                                );
278	                                p = nextP;
279	                            }
280	                        }
281	                    });
282	
283	                    try {
284	                        responseObj =
285	                            recursivelyConsolidate(seqResponses, tokenFn, mapper, 500_000);
286	                    } catch (Exception e) {
287	                        // LLM consolidation failed (e.g. API timeout). Rather than discard all the
288	                        // per-chunk work, merge the partial analyses locally so the user still gets
289	                        // a usable summary.
290	                        System.err.println(
291	                            "Consolidation failed; using local merge fallback: " + e.getMessage()
292	                        );
293	                        responseObj = localMerge(seqResponses);
294	                        consolidationFellBack = true;
295	                    } finally {
296	                        consolidationDone.set(true);
297	                        fakeProgress.cancel(true);
298	                    }
299	                }
300	
301	                progressMap.put(id, new ProgressState(100, "Done"));
302	
303	                String jsonResponse = mapper.writeValueAsString(responseObj);
304	
305	                // Don't persist a degraded local-merge fallback: the consolidation failure was
306	                // likely transient, so a later (non-forced) load should retry the LLM rather than
307	                // serve the cruder summary.
308	                if (consolidationFellBack) {
309	                    return jsonResponse;
310	                }
311	
312	                String title = responseObj.shortTitle();
313	                try {
314	                    if (external) {
315	                        source.get().writeCache(id, jsonResponse, title);
316	                    } else {
317	                        // The short title is best-effort; a failure here must not block caching or
318	                        // returning the summary.
319	                        try {
320	                            if (title != null && !title.isEmpty()) {
321	                                Files.writeString(shortTitlePath, title.trim());
322	                            }
323	                        } catch (Exception ignore) {}
324	                        Files.writeString(summaryJsonPath, jsonResponse);
325	                    }
326	                    return jsonResponse;
327	                } catch (Exception e) {
328	                    throw new Exception("Invalid JSON response");
329	                }
330	            } catch (Exception e) {
331	                System.err.println("Exception caught during analysis:");
332	                e.printStackTrace();
333	                try {
334	                    return mapper.writeValueAsString(
335	                        Map.of("summary", "Error generating summary: " + e.getMessage())
336	                    );
337	                } catch (Exception ex) {
338	                    return "{\"summary\": \"Error generating summary: Unknown error\"}";
339	                }
340	            } finally {
341	                progressMap.remove(id);
342	            }
343	        } finally {
344	            runningTasks.remove(id);
345	        }
346	    }
347	
348	    private AnalysisResponse recursivelyConsolidate(
349	        List<AnalysisResponse> responses,
350	        ToIntFunction<String> tokenFn,
351	        ObjectMapper mapper,
352	        int maxTokens
353	    ) throws Exception {
354	        String json = mapper.writeValueAsString(responses);
355	        boolean withinBudget;
356	        try {
357	            withinBudget = tokenFn.applyAsInt(json) <= maxTokens;
358	        } catch (Exception e) {
359	            // Only token estimation is best-effort here; fall back to a char-length heuristic so a
360	            // failed estimate doesn't get mistaken for a failed consolidation.
361	            withinBudget = (json.length() / 4) <= maxTokens;
362	        }
363	        // A consolidation failure below propagates to the caller (which falls back to a local merge).
364	        if (withinBudget || responses.size() <= 1) {
365	            return analyzerService.consolidateAnalysis(json);
366	        }
367	
368	        int mid = responses.size() / 2;
369	        AnalysisResponse r1 = recursivelyConsolidate(
370	            responses.subList(0, mid),
371	            tokenFn,
372	            mapper,
373	            maxTokens
374	        );
375	        AnalysisResponse r2 = recursivelyConsolidate(
376	            responses.subList(mid, responses.size()),
377	            tokenFn,
378	            mapper,
379	            maxTokens
380	        );
381	        return analyzerService.consolidateAnalysis(mapper.writeValueAsString(List.of(r1, r2)));
382	    }
383	
384	    /**
385	     * Deterministically merges per-chunk analyses without calling the LLM. Used as a fallback when
386	     * LLM consolidation fails, so the user still gets a usable (if less polished) summary instead of
387	     * an error.
388	     */
389	    private AnalysisResponse localMerge(List<AnalysisResponse> responses) {
390	        String shortTitle = "Session analysis";
391	        StringBuilder summary = new StringBuilder();
392	        List<String> flow = new ArrayList<>();
393	        List<AgentAction> actions = new ArrayList<>();
394	        List<Issue> issues = new ArrayList<>();
395	        List<String> recommendations = new ArrayList<>();
396	
397	        for (AnalysisResponse r : responses) {
398	            if (r == null) continue;
399	            if (
400	                "Session analysis".equals(shortTitle) &&
401	                r.shortTitle() != null &&
402	                !r.shortTitle().isBlank()
403	            ) {
404	                shortTitle = r.shortTitle();
405	            }
406	            if (r.summary() != null && !r.summary().isBlank()) {
407	                if (summary.length() > 0) summary.append(" ");
408	                summary.append(r.summary().trim());
409	            }
410	            if (r.flow() != null) {
411	                for (String f : r.flow()) if (f != null && !flow.contains(f)) flow.add(f);
412	            }
413	            if (r.agentActions() != null) actions.addAll(r.agentActions());
414	            if (r.issues() != null) issues.addAll(r.issues());
415	            if (r.recommendations() != null) {
416	                for (String rec : r.recommendations()) {
417	                    if (rec != null && !recommendations.contains(rec)) recommendations.add(rec);
418	                }
419	            }
420	        }
421	
422	        String summaryText = summary.length() > 4000
423	            ? summary.substring(0, 4000) + "..."
424	            : summary.toString();
425	        summaryText =
426	            "(Combined from " +
427	            responses.size() +
428	            " partial analyses; full consolidation was unavailable.) " +
429	            summaryText;
430	
431	        return new AnalysisResponse(
432	            shortTitle,
433	            cap(flow, 40),
434	            cap(actions, 40),
435	            cap(issues, 40),
436	            cap(recommendations, 30),
437	            summaryText
438	        );
439	    }
440	
441	    private static <T> List<T> cap(List<T> list, int max) {
442	        return list.size() > max ? new ArrayList<>(list.subList(0, max)) : list;
443	    }
444	}
