package io.github.glaforge.agybrainviz;

import io.micronaut.serde.annotation.Serdeable;
import java.util.List;

/**
 * The graded result for one session's analysis: an overall 0-100 {@code score} and which named
 * quality checks {@code passed} / {@code failed}.
 */
@Serdeable
public record EvalCaseResult(
    String sessionId,
    String title,
    int score,
    List<String> passed,
    List<String> failed
) {}

/*
