134	        }
135	        return step;
136	    }
137	
138	    private static ObjectNode reasoningStep(JsonNode payload, String ts) {
139	        String text = joinTextParts(payload.path("summary"));
140	        // Reasoning summaries are frequently empty/encrypted; only emit a step when there is text.
141	        if (text.isBlank()) return null;
142	        ObjectNode step = newStep(ts);
143	        step.put("type", "REASONING");
144	        step.put("source", "MODEL");
145	        step.put("thinking", text);
146	        return step;
147	    }
