164	     * falling back to the first user {@code response_item} message.
165	     *
166	     * @param lines the raw JSONL lines of a Codex rollout file
167	     * @return the derived summary text, if any
168	     */
169	    static Optional<String> deriveSummary(List<String> lines) {
170	        String fallback = null;
171	        for (String line : lines) {
172	            if (line == null || line.isBlank()) continue;
173	            try {
174	                JsonNode root = MAPPER.readTree(line);
175	                JsonNode payload = root.path("payload");
176	                String outer = root.path("type").asText("");
177	                if (
178	                    "event_msg".equals(outer) &&
179	                    "user_message".equals(payload.path("type").asText(""))
180	                ) {
181	                    String msg = payload.path("message").asText("");
182	                    if (!msg.isBlank()) return Optional.of(summarize(msg));
183	                } else if (
184	                    fallback == null &&
185	                    "response_item".equals(outer) &&
186	                    "message".equals(payload.path("type").asText("")) &&
187	                    "user".equals(payload.path("role").asText(""))
188	                ) {
189	                    String text = joinTextParts(payload.path("content"));
190	                    if (!text.isBlank()) fallback = summarize(text);
191	                }
192	            } catch (Exception e) {
193	                // skip malformed lines
194	            }
195	        }
196	        return Optional.ofNullable(fallback);
197	    }
198	
199	    private static ObjectNode newStep(String ts) {
200	        ObjectNode step = MAPPER.createObjectNode();
201	        if (ts != null && !ts.isBlank()) step.put("created_at", ts);
202	        return step;
203	    }
204	
205	    private static String joinTextParts(JsonNode parts) {
206	        if (parts == null || !parts.isArray()) return "";
207	        StringBuilder sb = new StringBuilder();
208	        for (JsonNode part : parts) {
209	            JsonNode text = part.get("text");
210	            if (text != null && text.isTextual()) {
211	                if (sb.length() > 0) sb.append("\n");
212	                sb.append(text.asText());
213	            }
214	        }
215	        return sb.toString();
216	    }
217	
218	    private static JsonNode parseArguments(String arguments) {
219	        if (arguments == null || arguments.isBlank()) {
220	            return MAPPER.createObjectNode();
221	        }
222	        try {
223	            return MAPPER.readTree(arguments);
224	        } catch (Exception e) {
225	            return MAPPER.getNodeFactory().textNode(arguments);
226	        }
227	    }
228	
229	    private static String outputText(JsonNode output) {
230	        if (output == null || output.isNull() || output.isMissingNode()) return "";
231	        return output.isTextual() ? output.asText() : output.toString();
232	    }
233	
234	    private static boolean isFailure(String output) {
235	        Matcher m = EXIT_CODE.matcher(output);
236	        return m.find() && !"0".equals(m.group(1));
237	    }
238	
239	    private static String summarize(String text) {
240	        String trimmed = text.strip();
241	        return trimmed.length() > 80 ? trimmed.substring(0, 80) + "..." : trimmed;
242	    }
243	}
