// Renders the saved eval run history into CSV so the quality trend can go into a spreadsheet.
// Pure (no DOM); the browser download is handled by downloadText in mine-export.js.

const COLUMNS = [
  "savedAt",
  "flavor",
  "modelLabel",
  "sessionCount",
  "evaluatedSessions",
  "avgScore",
  "judged",
  "judgedSessions",
  "avgFaithfulness",
  "avgActionability",
  "avgClarity",
];

// Quote a cell only when it contains a comma, quote, or newline; double embedded quotes (RFC 4180).
function csvCell(value) {
  const s = value === null || value === undefined ? "" : String(value);
  return /[",\n]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s;
}

/** A CSV document (header row + one row per saved run) for a run-history list. */
export function historyCsv(history) {
  const runs = Array.isArray(history) ? history : [];
  const rows = runs.map((run) => COLUMNS.map((col) => csvCell(run[col])).join(","));
  return [COLUMNS.join(","), ...rows].join("\n") + "\n";
}

